def run(controller):
    controller.reset()
    limits = controller.get_limits()

    if limits['maximum_signal'] >= 40000:
        gain = 64
    else:
        gain = 16

    controller.configure(100, 999, gain)
    controller.set_rgb(40, 60, 20)
    result = controller.measure()

    valid = False

    for _ in range(4):
        spectrum = result['spectrum']
        min_sig = result['minimum_signal']
        max_sig = result['maximum_signal']

        valid = True
        for ch in spectrum:
            val = spectrum[ch]
            if not (val >= 0 and val <= max_sig):
                valid = False

        if min_sig < 1:
            valid = False

        if valid:
            pass
        else:
            gain = gain / 4
            if gain < 1:
                gain = 1
            controller.configure(100, 999, gain)
            controller.set_rgb(40, 60, 20)
            result = controller.measure()

    controller.clear()
    return result

